-- Creating schema and table
CREATE SCHEMA IF NOT EXISTS gnaf_201702;
DROP TABLE IF EXISTS gnaf_201702.addresses;
CREATE TABLE gnaf_201702.addresses (
  gnaf_pid varchar(255),
  street_name varchar(255),
  locality_name varchar(255),
  postcode varchar(255),
  alias_principal varchar(1),
  mb_2011_code varchar(255),
  number_first varchar(255),
  elector_name varchar(255),
  gender varchar(10),
  age varchar(10)
);


CREATE INDEX idx_addresses_mb ON gnaf_201702.addresses(mb_2011_code);
